// App.js
import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Outlet } from 'react-router-dom';
import './globals.css';
import './public.css';
import './student.css';

// --- COMPONENTS & PUBLIC PAGES ---
import Navbar from './components/Navbar';
import Home from './pages/Home';
import InternshipList from './pages/InternshipList';
import InternshipDetails from './pages/InternshipDetails';
import TrainingList from './pages/TrainingList';
import Login from './pages/Login';
import Register from './pages/Register';

// --- STUDENT PAGES (Paths are now corrected to match your folder structure) ---
import StudentNavbar from './components/StudentNavbar';
import BrowseInternships from './pages/student/BrowseInternships'; // <-- CORRECT PATH
import MyApplications from './pages/student/MyApplications';     // <-- CORRECT PATH
import MyTrainings from './pages/student/MyTrainings';         // <-- CORRECT PATH
import StudentProfile from './pages/student/StudentProfile';       // <-- CORRECT PATH

export default function App() {
  const [user, setUser] = useState(null); 

  const handleLogin = (role) => {
    setUser({ role: role, name: 'Guest Student' });
  };

  const handleLogout = () => {
    setUser(null);
  };

  // --- LAYOUT WRAPPERS ---
  const PublicLayout = () => {
    if (user && user.role === 'student') {
      return <Navigate to="/student/browse" replace />;
    }
    return (
      <>
        <Navbar />
        <main style={{ paddingTop: 'var(--nav-height)' }}>
          <Outlet />
        </main>
      </>
    );
  };

  const StudentLayout = () => {
    if (!user || user.role !== 'student') {
      return <Navigate to="/login" replace />;
    }
    return (
      <div className="student-dashboard">
        <StudentNavbar logout={handleLogout} />
        <main className="dashboard-content" style={{ paddingTop: 'var(--nav-height)' }}>
          <Outlet />
        </main>
      </div>
    );
  };

  return (
    <Router>
      <Routes>

        {/* PUBLIC ROUTES */}
        <Route element={<PublicLayout />}>
          <Route path="/" element={<Home />} />
          <Route path="/internships" element={<InternshipList />} />
          <Route path="/internships/:id" element={<InternshipDetails />} />
          <Route path="/trainings" element={<TrainingList />} />
          <Route path="/login" element={<Login onLogin={handleLogin} />} />
          <Route path="/register" element={<Register onRegister={handleLogin} />} />
        </Route>

        {/* STUDENT ROUTES */}
        <Route path="/student" element={<StudentLayout />}>
          <Route path="browse" element={<BrowseInternships />} />
          <Route path="applications" element={<MyApplications />} />
          <Route path="trainings" element={<MyTrainings />} />
          <Route path="profile" element={<StudentProfile />} />
        </Route>

      </Routes>
    </Router>
  );
}
